const CHAIN_ID = Number(process.env.CHAIN_ID || '1');

if (!RPC_URL) throw new Error('Missing RPC_URL');
if (!PRIVATE_KEY) throw new Error('Missing PRIVATE_KEY');

const provider = new ethers.JsonRpcProvider(RPC_URL, CHAIN_ID);
const wallet = new ethers.Wallet(PRIVATE_KEY, provider);

async function getWalletAddress() {
  return await wallet.getAddress();
}

async function getEthBalance(address) {
  const target = address || (await wallet.getAddress());
  return await provider.getBalance(target);
}

async function sendEth(to, amountEth, options = {}) {
  if (!ethers.isAddress(to)) throw new Error('Invalid recipient address');

  const value = ethers.parseEther(String(amountEth));
  const txRequest = {
    to,
    value,
  };

  if (options.gasLimit) txRequest.gasLimit = BigInt(options.gasLimit);
  if (options.maxFeePerGas) txRequest.maxFeePerGas = ethers.parseUnits(String(options.maxFeePerGas), 'gwei');
  if (options.maxPriorityFeePerGas) txRequest.maxPriorityFeePerGas = ethers.parseUnits(String(options.maxPriorityFeePerGas), 'gwei');
  if (options.gasPrice) txRequest.gasPrice = ethers.parseUnits(String(options.gasPrice), 'gwei');
  if (options.nonce !== undefined) txRequest.nonce = Number(options.nonce);
  if (options.chainId !== undefined) txRequest.chainId = Number(options.chainId);

  const tx = await wallet.sendTransaction(txRequest);
  const receipt = await tx.wait();
  return { txHash: tx.hash, receipt };
}

